Berikut implementasi fungsi `diff_dicts` untuk perbandingan rekursif dua dictionary. Fungsi ini mendeteksi key yang `added`, `removed`, dan `modified`.

```python
from typing import Any, Dict, Tuple

def diff_dicts(dict1: Dict[str, Any], dict2: Dict[str, Any]) -> Dict[str, Any]:
    """
    Melakukan diff rekursif antara dua dictionary.
    Returns: Dictionary berisi 'added', 'removed', dan 'modified'.
    """
    diff = {
        'added': {},
        'removed': {},
        'modified': {}
    }

    keys1 = set(dict1.keys())
    keys2 = set(dict2.keys())

    # Key yang ada di dict2 tapi tidak di dict1 (Added)
    for key in keys2 - keys1:
        diff['added'][key] = dict2[key]

    # Key yang ada di dict1 tapi tidak di dict2 (Removed)
    for key in keys1 - keys2:
        diff['removed'][key] = dict1[key]

    # Key yang ada di keduanya (Check Modified or Nested)
    for key in keys1 & keys2:
        val1 = dict1[key]
        val2 = dict2[key]

        if isinstance(val1, dict) and isinstance(val2, dict):
            # Rekursif untuk nested dict
            nested_diff = diff_dicts(val1, val2)
            # Hanya masukkan jika ada perubahan signifikan
            if any(nested_diff.values()):
                diff['modified'][key] = nested_diff
        elif val1 != val2:
            # Value berbeda dan bukan dict
            diff['modified'][key] = {
                'old': val1,
                'new': val2
            }

    return diff

# Contoh Penggunaan
